import React from "react";
import styled from "styled-components";
import myPhoto from "../../../assets/images/I.jpg"

export const Main = () => {
    return (
        <div>
            <div>
                <span>Hi there</span>
                <h2>I am Pavel Sasim</h2>
                <h1>A Front-end Developer</h1>
            </div>
            
            <MyPhoto src={myPhoto} alt="" />
        </div>
    )
}


const MyPhoto = styled.img`
    width: 500px;
    height: 700px;
`
